const records = response.records || [];

return records.map(r => ({
  json: {
    recordId: r.id,
    name: r.fields.Name || '',
    email: r.fields.Email || '',
    message: r.fields.Message || '',
    category: r.fields.Category || '',
  }
}));

const response = $input.first().json;
const lead = $('Build Follow-up Prompt').item.json;

let content = '';
try {
  content = response.choices[0].message.content;
} catch (e) {
  content = '';
}

content = String(content || '').trim();
if (content.startsWith('```')) {
  content = content.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();
}

let parsed = null;
try {
  parsed = JSON.parse(content);
} catch (e) {
  parsed = null;
}

let reply_subject = '';
let reply_body = '';

if (parsed && typeof parsed === 'object') {
  reply_subject = String(parsed.reply_subject || '').trim();
  reply_body = String(parsed.reply_body || '').trim();
}

if (!reply_subject) {
  reply_subject = 'Following up on your inquiry';
}
if (!reply_body) {
  reply_body = 'Hi ' + (lead.name || 'there') + ',\n\nJust checking in on your recent inquiry with Bloom Studio, we would love to help if you are still interested. Let us know if you would like to move forward or if you have any questions.\n\nWarm regards,\nThe Bloom Studio Team';
}

return [{
  json: {
    recordId: lead.recordId,
    email: lead.email,
    name: lead.name,
    reply_subject,
    reply_body,
  }
}];
